-- Insert 50 kettlebell strength exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Kettlebell Goblet Squat', 'kettlebell-goblet-squat', 'Perform Kettlebell Goblet Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'BEGINNER', 8, 3, 6, NULL, 75, 45, 'Kettlebell Goblet Squat is a kettlebell-loaded strength exercise for front-loaded squat strength, bracing, and repeatable depth. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.', 'Primary subrole: Goblet squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Goblet squat strength', 'capacity', 'squat_knee_dominant_strength', 'kettlebell_goblet_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","anterior_core"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Goblet Squat trains front-loaded squat strength, bracing, and repeatable depth using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the pattern with control while keeping the kettlebell close and posture organized.","Reach the target range only if the athlete can own the feet, knees, hips, and trunk.","Stand or return with strong intent without bouncing, twisting, or chasing speed.","Finish each rep looking ready to repeat the same rep again."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."]}'::jsonb),
  ('Double Kettlebell Front Squat', 'double-kettlebell-front-squat', 'Perform Double Kettlebell Front Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'INTERMEDIATE', 8, 3, 6, NULL, 90, 45, 'Double Kettlebell Front Squat is a kettlebell-loaded strength exercise for higher-load front-rack squat strength with strong trunk and upper-back demand. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.', 'Primary subrole: Double front-rack squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Double front-rack squat strength', 'capacity', 'squat_knee_dominant_strength', 'double_kettlebell_front_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","front_rack_support","trunk_bracing"],"primary_tissues":["quadriceps","glutes","upper_back","anterior_core"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Double Kettlebell Front Squat trains higher-load front-rack squat strength with strong trunk and upper-back demand using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the pattern with control while keeping the kettlebell close and posture organized.","Reach the target range only if the athlete can own the feet, knees, hips, and trunk.","Stand or return with strong intent without bouncing, twisting, or chasing speed.","Finish each rep looking ready to repeat the same rep again."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."]}'::jsonb),
  ('Single Kettlebell Front-Rack Squat', 'single-kettlebell-front-rack-squat', 'Perform Single Kettlebell Front-Rack Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'BEGINNER', 8, 3, 6, NULL, 90, 45, 'Single Kettlebell Front-Rack Squat is a kettlebell-loaded strength exercise for front-rack squat strength with offset trunk control and anti-rotation demand. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.', 'Primary subrole: Offset front-rack squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Offset front-rack squat strength', 'capacity', 'squat_knee_dominant_strength', 'single_kettlebell_front_rack_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","front_rack_support","anti_rotation_bracing"],"primary_tissues":["quadriceps","glutes","obliques","upper_back"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Single Kettlebell Front-Rack Squat trains front-rack squat strength with offset trunk control and anti-rotation demand using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the pattern with control while keeping the kettlebell close and posture organized.","Reach the target range only if the athlete can own the feet, knees, hips, and trunk.","Stand or return with strong intent without bouncing, twisting, or chasing speed.","Finish each rep looking ready to repeat the same rep again."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."]}'::jsonb),
  ('Heels-Elevated Kettlebell Goblet Squat', 'heels-elevated-kettlebell-goblet-squat', 'Perform Heels-Elevated Kettlebell Goblet Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'BEGINNER', 8, 3, 6, NULL, 75, 45, 'Heels-Elevated Kettlebell Goblet Squat is a kettlebell-loaded strength exercise for knee-flexion and quadriceps-biased strength through a usable deep squat range. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.', 'Primary subrole: Quad-biased goblet squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Quad-biased goblet squat strength', 'capacity', 'squat_knee_dominant_strength', 'heels_elevated_kettlebell_goblet_squat_strength', '{"primary_joint_actions":["knee_flexion_extension","hip_flexion_extension","ankle_dorsiflexion","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Heels-Elevated Kettlebell Goblet Squat trains knee-flexion and quadriceps-biased strength through a usable deep squat range using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the pattern with control while keeping the kettlebell close and posture organized.","Reach the target range only if the athlete can own the feet, knees, hips, and trunk.","Stand or return with strong intent without bouncing, twisting, or chasing speed.","Finish each rep looking ready to repeat the same rep again."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range."]}'::jsonb),
  ('Kettlebell Box Squat', 'kettlebell-box-squat', 'Perform Kettlebell Box Squat as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'BEGINNER', 8, 3, 6, NULL, 75, 45, 'Kettlebell Box Squat is a kettlebell-loaded strength exercise for position consistency, depth control, and force production from a repeatable target. Strength is the primary score; explosiveness is delivery-dependent and never the main intent.', 'Primary subrole: Box-supported squat strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Box-supported squat strength', 'capacity', 'squat_knee_dominant_strength', 'kettlebell_box_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","controlled_sit_to_stand","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","spinal_erectors"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Box Squat trains position consistency, depth control, and force production from a repeatable target using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a kettlebell load the athlete can control for every rep.","Set feet, grip, ribs, and pelvis before beginning the movement.","Brace and breathe so the bell stays close to the body and the rep path stays repeatable."],"execution_steps":["Lower into the pattern with control while keeping the kettlebell close and posture organized.","Reach the target range only if the athlete can own the feet, knees, hips, and trunk.","Stand or return with strong intent without bouncing, twisting, or chasing speed.","Finish each rep looking ready to repeat the same rep again."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Foot tripod, knees track, chest/ribs stacked.","Stand through the floor, not around the position.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Knees collapse inward or feet lose tripod pressure.","Depth is forced by rounding the spine instead of owning hip and ankle range.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading."]}'::jsonb),
