  ('Kettlebell Overhead Carry', 'kettlebell-overhead-carry', 'Perform Kettlebell Overhead Carry as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'INTERMEDIATE', 8, 3, NULL, 30, 90, 60, 'Kettlebell Overhead Carry is a kettlebell-loaded strength exercise for shoulder strength and trunk stiffness under a long-lever overhead load. Strength and control are the primary scores; explosiveness should not be treated as the main intent.', 'Primary subrole: Overhead carry strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Overhead carry strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'kettlebell_overhead_carry_strength', '{"primary_joint_actions":["overhead_lockout","loaded_gait","ribcage_control","shoulder_stability"],"primary_tissues":["deltoids","triceps","rotator_cuff","obliques","upper_back"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Overhead Carry trains shoulder strength and trunk stiffness under a long-lever overhead load using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a clear walking lane with enough space to stop safely.","Pick up the kettlebell(s) with a hinge, pack the shoulders, and stand tall before moving.","Set ribs over pelvis, eyes forward, and grip the handle without shrugging or leaning."],"execution_steps":["Stand tall with the kettlebell(s) under control before the first step.","Walk with quiet, short-to-moderate steps while keeping ribs stacked and shoulders packed.","Keep the bell path stable and avoid leaning, rushing, or turning the carry into conditioning.","Set the bell down with a hinge only after posture and grip are still controlled."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Walk tall; bell quiet; ribs over pelvis.","Small strong steps, no lean."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Leaning away from the load or letting the shoulders ride up.","Walking too fast and losing posture before the target distance."]}'::jsonb),
  ('Kettlebell Bottoms-Up Carry', 'kettlebell-bottoms-up-carry', 'Perform Kettlebell Bottoms-Up Carry as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'INTERMEDIATE', 8, 3, NULL, 30, 90, 60, 'Kettlebell Bottoms-Up Carry is a kettlebell-loaded strength exercise for grip, shoulder, and trunk strength under an unstable upright bell position. Strength and control are the primary scores; explosiveness should not be treated as the main intent.', 'Primary subrole: Bottoms-up carry strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Bottoms-up carry strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'kettlebell_bottoms_up_carry_strength', '{"primary_joint_actions":["bottoms_up_grip_support","loaded_gait","shoulder_packing","trunk_bracing"],"primary_tissues":["forearm_grip","rotator_cuff","deltoids","obliques","upper_back"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Bottoms-Up Carry trains grip, shoulder, and trunk strength under an unstable upright bell position using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Choose a clear walking lane with enough space to stop safely.","Pick up the kettlebell(s) with a hinge, pack the shoulders, and stand tall before moving.","Set ribs over pelvis, eyes forward, and grip the handle without shrugging or leaning."],"execution_steps":["Stand tall with the kettlebell(s) under control before the first step.","Walk with quiet, short-to-moderate steps while keeping ribs stacked and shoulders packed.","Keep the bell path stable and avoid leaning, rushing, or turning the carry into conditioning.","Set the bell down with a hinge only after posture and grip are still controlled."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Walk tall; bell quiet; ribs over pelvis.","Small strong steps, no lean."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Leaning away from the load or letting the shoulders ride up.","Walking too fast and losing posture before the target distance."]}'::jsonb),
  ('Kettlebell Turkish Get-Up', 'kettlebell-turkish-get-up', 'Perform Kettlebell Turkish Get-Up as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'ADVANCED', 8, 3, 3, NULL, 90, 60, 'Kettlebell Turkish Get-Up is a kettlebell-loaded strength exercise for whole-body strength, shoulder ownership, and trunk control through multiple positions. Strength and control are the primary scores; explosiveness should not be treated as the main intent.', 'Primary subrole: Get-up strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Get-up strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'kettlebell_turkish_get_up_strength', '{"primary_joint_actions":["loaded_roll_to_elbow","shoulder_lockout","hip_bridge","half_kneeling_transition","loaded_stand"],"primary_tissues":["rotator_cuff","deltoids","obliques","glutes","quadriceps","forearm_grip"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Turkish Get-Up trains whole-body strength, shoulder ownership, and trunk control through multiple positions using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Start with a light kettlebell and rehearse the bodyweight path first.","Set the working shoulder, wrist, ribs, and eyes before the loaded rep begins.","Clear the space around the athlete so the bell can be lowered safely at any point."],"execution_steps":["Roll to the elbow and hand while keeping the kettlebell stacked over the shoulder.","Bridge or sweep the leg into a stable half-kneeling position without losing the overhead line.","Stand tall under control, then reverse the same path back to the floor.","Pause at each checkpoint long enough to prove the shoulder, trunk, and hip positions are owned."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch.","Stack wrist over elbow; press from a packed shoulder.","Ribs down as the bell moves."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading.","Pressing with rib flare, neck tension, or wrist collapse.","Losing shoulder position at the bottom or overhead finish."]}'::jsonb),
  ('Kettlebell Windmill', 'kettlebell-windmill', 'Perform Kettlebell Windmill as a controlled, progressively loaded kettlebell strength pattern. Load, range, tempo, and rest should support force production rather than fatigue chasing or ballistic work.', 'ADVANCED', 8, 3, 3, NULL, 90, 60, 'Kettlebell Windmill is a kettlebell-loaded strength exercise for loaded hinge-rotation strength with shoulder stability and trunk control. Strength and control are the primary scores; explosiveness should not be treated as the main intent.', 'Primary subrole: Windmill strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not reframe this card as a swing, snatch, jump, plyometric, or conditioning station.', 'Set the position first, move the kettlebell with control, and finish every rep like you could repeat it cleanly.', 'Windmill strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'kettlebell_windmill_strength', '{"primary_joint_actions":["hip_hinge_with_rotation","overhead_lockout","thoracic_rotation_control","anti_lateral_flexion"],"primary_tissues":["obliques","glutes","hamstrings","rotator_cuff","upper_back"],"primary_motor_control_demands":["brace_before_load","controlled_eccentric","repeatable_rep_path"],"postural_shape":"stacked_ribs_pelvis_with_kettlebell_control","breathing_demand":"brace_with_controlled_exhale_no_prolonged_breath_holding","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Kettlebell Windmill trains loaded hinge-rotation strength with shoulder stability and trunk control using kettlebell resistance. The athlete organizes the body first, creates tension through the handle and floor, moves through a range they own, and stops the set before technique breaks.","setup":["Start with a light kettlebell and rehearse the bodyweight path first.","Set the working shoulder, wrist, ribs, and eyes before the loaded rep begins.","Clear the space around the athlete so the bell can be lowered safely at any point."],"execution_steps":["Set the kettlebell overhead and angle the feet so the hips can hinge safely.","Push the hips back and rotate the torso only as far as shoulder position remains stacked.","Drive through the hips and trunk to return to standing without bending the overhead arm.","Move slowly enough that the bell, ribs, and pelvis stay organized the entire rep."],"coach_cues":["Own the start before the rep starts.","Strong, controlled, repeatable.","Brace, then move the bell.","Hips back, spine long, bell close.","Finish tall with glutes, not low-back arch.","Rotate only through the range you own.","Shoulder stacked, hips do the work."],"common_faults":["Chasing load after position quality breaks.","Turning the set into a rushed conditioning station instead of strength work.","Rounding the back or reaching the bell away from the body.","Squatting the hinge when the goal is posterior-chain loading.","Rotating through the low back instead of controlling hips, ribs, and shoulder stack."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

